// ============================================
// ELAB GDPR Service v2.1 — FIX email null
// Property names: italiano (come nel DB Notion)
// Select values: italiano (come nel DB Notion)
// FIX: email vuota → null (Notion rifiuta "")
// © Andrea Marro — 19/02/2026
// ============================================

const https = require('https');
const crypto = require('crypto');

const NOTION_TOKEN = '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';
const NOTION_VERSION = '2022-06-28';
const NOTION_DB = 'e2e0c070-301b-4813-a7c5-378a2d46758a';

function notionReq(method, path, payload) {
  return new Promise((resolve, reject) => {
    const data = payload ? JSON.stringify(payload) : null;
    const opts = {
      hostname: 'api.notion.com',
      path: '/v1' + path,
      method: method,
      headers: {
        'Authorization': 'Bearer ' + NOTION_TOKEN,
        'Notion-Version': NOTION_VERSION,
        'Content-Type': 'application/json'
      }
    };
    if (data) opts.headers['Content-Length'] = Buffer.byteLength(data);
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(body);
          if (res.statusCode >= 400) reject(new Error('Notion ' + res.statusCode + ': ' + (parsed.message || JSON.stringify(parsed).substring(0, 300))));
          else resolve(parsed);
        } catch { reject(new Error('Invalid JSON: ' + body.substring(0, 200))); }
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('Timeout')); });
    if (data) req.write(data);
    req.end();
  });
}

async function notionCreate(properties) {
  // Rimuovi proprietà con valore undefined
  const clean = {};
  for (const [k, v] of Object.entries(properties)) {
    if (v !== undefined) clean[k] = v;
  }
  return await notionReq('POST', '/pages', {
    parent: { database_id: NOTION_DB },
    properties: clean
  });
}

async function notionQuery(filter) {
  return await notionReq('POST', '/databases/' + NOTION_DB + '/query', { filter });
}

async function notionUpdate(pageId, properties) {
  return await notionReq('PATCH', '/pages/' + pageId, { properties });
}

const textProp = (v) => ({ rich_text: [{ text: { content: String(v || '') } }] });
const titleProp = (v) => ({ title: [{ text: { content: String(v || '') } }] });
const selectProp = (v) => ({ select: { name: String(v || '') } });
// FIX: Notion rifiuta { email: "" } — deve essere null o email valida
const emailProp = (v) => v ? ({ email: String(v) }) : undefined;
const numProp = (v) => ({ number: Number(v) || 0 });
const checkProp = (v) => ({ checkbox: Boolean(v) });
const dateProp = (v) => ({ date: { start: v || new Date().toISOString() } });

// === Input ===
let rawInput = null;
let body = null;
try {
  rawInput = $input.first().json;
  body = rawInput.body || rawInput;
} catch (e) {
  return [{ json: { success: false, error: 'INPUT_ERROR: ' + e.message } }];
}

const action = body.action || 'unknown';

const debug = {
  receivedAction: action,
  bodyKeys: Object.keys(body),
  dbId: NOTION_DB
};

let result = { success: false, action };

try {
  if (action === 'delete') {
    const page = await notionCreate({
      'Name': titleProp('DEL-' + Date.now()),
      'Tipo': selectProp('Eliminazione Dati'),
      'User ID': textProp(body.userId),
      'Motivo': textProp(body.reason),
      'Stato': selectProp('Ricevuta'),
      'Data Richiesta': dateProp(),
      'Email': emailProp(body.email)
    });
    result = { success: true, action, pageId: page.id, message: 'Richiesta eliminazione registrata', _debug: debug };

  } else if (action === 'parental-consent') {
    const token = 'tok_' + crypto.randomUUID().replace(/-/g, '').substring(0, 24);
    const page = await notionCreate({
      'Name': titleProp('PC-' + Date.now()),
      'Tipo': selectProp('Consenso Parentale'),
      'User ID': textProp(body.userId || ''),
      'Età Minore': numProp(body.childAge),
      'Email Genitore': emailProp(body.parentEmail),
      'Nome Genitore': textProp(body.parentName),
      'Metodo Consenso': selectProp(body.consentMethod === 'signature' ? 'Firma Digitale' : 'Email'),
      'COPPA': checkProp(body.requiresCOPPA),
      'Stato': selectProp('In Attesa Verifica'),
      'Token Verifica': textProp(token),
      'Data Richiesta': dateProp(),
      'Dettagli': textProp(body.childName ? 'Nome minore: ' + body.childName : '')
    });
    result = { success: true, action, pageId: page.id, token, message: 'Richiesta consenso parentale registrata', _debug: debug };

  } else if (action === 'export') {
    const page = await notionCreate({
      'Name': titleProp('EXP-' + Date.now()),
      'Tipo': selectProp('Esportazione Dati'),
      'User ID': textProp(body.userId),
      'Stato': selectProp('Ricevuta'),
      'Data Richiesta': dateProp(),
      'Email': emailProp(body.email)
    });
    result = { success: true, action, pageId: page.id, message: 'Richiesta esportazione registrata', _debug: debug };

  } else if (action === 'revoke') {
    const page = await notionCreate({
      'Name': titleProp('REV-' + Date.now()),
      'Tipo': selectProp('Revoca Consenso'),
      'User ID': textProp(body.userId),
      'Stato': selectProp('Completata'),
      'Data Richiesta': dateProp(),
      'Data Completamento': dateProp(),
      'Email': emailProp(body.email)
    });
    result = { success: true, action, pageId: page.id, message: 'Consenso revocato', _debug: debug };

  } else if (action === 'verify-parental-consent') {
    const qData = await notionQuery({
      property: 'Token Verifica',
      rich_text: { equals: body.token || '' }
    });
    if (qData.results && qData.results.length > 0) {
      const pageId = qData.results[0].id;
      await notionUpdate(pageId, {
        'Stato': selectProp('Completata'),
        'Data Completamento': dateProp()
      });
      result = { success: true, action, verified: true, message: 'Consenso verificato', _debug: debug };
    } else {
      result = { success: false, action, verified: false, message: 'Token non valido o scaduto', _debug: debug };
    }

  } else if (action === 'correct') {
    const page = await notionCreate({
      'Name': titleProp('COR-' + Date.now()),
      'Tipo': selectProp('Rettifica Dati'),
      'User ID': textProp(body.userId),
      'Dettagli': textProp(JSON.stringify(body.corrections || body.details || {})),
      'Stato': selectProp('Ricevuta'),
      'Data Richiesta': dateProp(),
      'Email': emailProp(body.email)
    });
    result = { success: true, action, pageId: page.id, message: 'Richiesta rettifica registrata', _debug: debug };

  } else {
    result = { success: false, action, message: 'Azione non riconosciuta: ' + action, _debug: debug };
  }
} catch (error) {
  result = { success: false, action, error: error.message, _debug: debug };
}

return [{ json: result }];
